// First, collect all input items from the previous node
const allItems = $items(); // $items() gives all input items as an array

// Separate stocks (first half) and prices (second half)
const stocks = allItems.slice(0, 5).map(item => item.json);
const prices = allItems.slice(5, 10).map(item => parseFloat(item.json.price));

// Combine stock with its corresponding price
return stocks.map((stock, i) => {
    const currentPrice = prices[i];
    const avgPrice = parseFloat(stock.avg_price);
    const changePercent = ((currentPrice - avgPrice) / avgPrice) * 100;
    const volatility = Math.abs(changePercent);

    const risks = [];
    if (changePercent <= stock.drop_threshold) risks.push("Large Price Drop");
    if (volatility >= stock.volatility_threshold) risks.push("High Volatility");

    return {
        json: {
            ...stock,
            current_price: currentPrice,
            change_percent: changePercent.toFixed(2),
            volatility: volatility.toFixed(2),
            risks
        }
    };
});

