// Collect all input items
const allItems = $items(); // gives array of all input items

// Map over items to format each stock
const flaggedStocksText = allItems.map(item => {
  const stock = item.json;
  return `Symbol: ${stock.symbol}
Current Price: ${stock.current_price}
Average Price: ${stock.avg_price}
Change Percent: ${stock.change_percent}%
Volatility: ${stock.volatility}%
Quantity: ${stock.quantity}
Sector: ${stock.sector}
Notes: ${stock.notes}
Risks: ${stock.risks.join(", ")}`;
}).join("\n\n"); // double newline for readability

// Return as single output
return [{ json: { output: flaggedStocksText } }];
